public class Mediator {
    static class EventBus {
        java.util.Map<String, java.util.List<Runnable>> listeners = new java.util.HashMap<>();
        void on(String event, Runnable handler) {
            listeners.computeIfAbsent(event, k -> new java.util.ArrayList<>()).add(handler);
        }
        void emit(String event) {
            listeners.getOrDefault(event, java.util.Collections.emptyList()).forEach(Runnable::run);
        }
    }
    public static void main(String[] args) {
        EventBus bus = new EventBus();
        bus.on("click", () -> System.out.println("A"));
        bus.on("click", () -> System.out.println("B"));
        bus.on("hover", () -> System.out.println("C"));
        bus.emit("click");
        bus.emit("hover");
        bus.emit("focus");
    }
}
